// Read webhook body explicitly since Workflow Constants (keepOnlySet) wipes $json
const webhookData = $('Webhook Trigger').first().json;
const b = webhookData.body ?? webhookData;
const run_id = b.run_id || b.runId || b.runID;
const query = b.enforced_query || b.query || b.enforcedQuery;
const max_results = Number(b.max_results ?? b.maxResults ?? 20);
if (!run_id || !query) {
  return [{ json: { ok:false, error:{code:'MISSING_FIELDS', message:'run_id and enforced_query are required'}, run_id: run_id ?? null, query: query ?? null, max_results } }];
}
return [{ json: { ok:true, run_id, query, max_results: Math.max(1, Math.min(20, max_results)), scope: b.scope ?? null, metro: b.metro ?? null } }];

const ni = $('Normalize Input').first().json;
const baseQuery = ni.query;
const max = ni.max_results || 10;
const neg = ' -"grant writing" -"grant writer" -"how to write a grant" -"grant template" -"grant course" -udemy -coursera';

const queries = [
  { query: baseQuery + neg, limit: max, variant: 'base' },
  { query: baseQuery + ' RFP RFA "request for proposals" "funding opportunity" "notice of funding"' + neg, limit: Math.min(max, 10), variant: 'rfp' },
  { query: baseQuery + ' foundation "grant program" "grant opportunity" digital equity broadband' + neg, limit: Math.min(max, 10), variant: 'foundation' }
];

return queries.map(q => ({ json: q }));

const ni = $('Normalize Input').first().json;
const run_id = ni.run_id;
const allItems = $input.all();

let allResults = [];
for (const item of allItems) {
  const d = item.json;
  const arr = d.data || d.results || (d.body && (d.body.data || d.body.results)) || [];
  if (Array.isArray(arr)) allResults = allResults.concat(arr);
}

// URL blocklist patterns for grants
const blockedUrlPatterns = [
  /udemy\.com/i, /coursera\.org/i, /skillshare\.com/i,
  /indeed\.com/i, /glassdoor\.com/i,
  /\/grant-writing-/i, /\/how-to-write/i, /\/grant-template/i,
  /youtube\.com\/watch/i
];

// Content blocklist keywords for grants
const blockedContentKeywords = [
  'grant writing course', 'learn grant writing', 'grant writing template',
  'grant writing certification', 'grant writing workshop',
  'grant writing tips', 'how to write a grant proposal',
  'enroll now', 'sign up for course'
];

let filtered_out = 0;
const seen = new Set();
const filtered = [];

for (const r of allResults) {
  const url = (r.url || r.link || r.source_url || '').trim();
  const title = (r.title || r.name || r.pageTitle || '').trim();
  const snippet = (r.description || r.snippet || r.text || r.summary || '').trim();
  const combined = (title + ' ' + snippet).toLowerCase();

  if (url && blockedUrlPatterns.some(p => p.test(url))) { filtered_out++; continue; }
  if (blockedContentKeywords.some(kw => combined.includes(kw))) { filtered_out++; continue; }

  const canonical = url.toLowerCase().replace(/\/$/, '').replace(/^https?:\/\/www\./, 'https://');
  if (canonical && seen.has(canonical)) { filtered_out++; continue; }
  if (canonical) seen.add(canonical);

  filtered.push({ title, url, snippet });
  if (filtered.length >= 20) break;
}

return [{ json: { run_id, filtered_results: filtered, filtered_out_count: filtered_out, has_results: filtered.length > 0 } }];

const prev = $('Merge & Pre-Filter').first().json;
const run_id = prev.run_id;
const results = prev.filtered_results || [];
const query = $('Normalize Input').first().json.query;

const CAP = 12000;
let search_context = 'Query: ' + query + '\n\nResults:\n';
let charCount = search_context.length;

for (let i = 0; i < results.length; i++) {
  const r = results[i];
  const entry = (i+1) + '. ' + (r.title ?? '') + '\nURL: ' + (r.url ?? '') + '\nSnippet: ' + (r.snippet ?? '');
  if (charCount + entry.length + 2 > CAP) break;
  search_context += entry + '\n\n';
  charCount += entry.length + 2;
}

return [{ json: { run_id, query, search_context } }];

let txt = $json?.choices?.[0]?.message?.content ?? '';
txt = String(txt).trim();
let parsed;
try { parsed = JSON.parse(txt); } catch(e) {
  const m = txt.match(/\[[\s\S]*\]/);
  if (m) parsed = JSON.parse(m[0]); else parsed = [];
}
const grants = Array.isArray(parsed) ? parsed : (parsed.grants || []);
const ni = $('Normalize Input').first().json;
const run_id = ni.run_id;
const max_results = Number(ni.max_results ?? 20);
const cleaned = grants.slice(0, max_results).map(g => ({
  title: g.name ?? 'Unknown Grant',
  description: [g.description, g.amount ? 'Amount: ' + g.amount : null, g.eligibility ? 'Eligibility: ' + g.eligibility : null].filter(Boolean).join(' | ') || null,
  url: g.url ?? null,
  source: 'firecrawl+llm',
  location: g.geography ?? null,
  date_info: g.deadline ?? null,
  organization: g.funder ?? null,
  contact_name: null,
  contact_email: null,
  contact_phone: null,
  confidence: (typeof g.confidence === 'number') ? g.confidence : null,
  raw_data: g
}));
return [{ json: { run_id, status: 'completed', results: cleaned } }];

const run_id = $('Normalize Input').first().json.run_id;
const filtered_out = $('Merge & Pre-Filter').first().json.filtered_out_count || 0;
return [{ json: { run_id, status: 'completed', results: [], meta: { filtered_out: true, filtered_out_count: filtered_out } } }];
